let StripeModel={creditcard:{async createCreditCard(data){let payload={email:data.email,stripe_credit_card:data.creditcard,card_brand:data.card_brand},response=await StripeServices.createCreditCard({payload:payload});if(response.state){if(!0===response.data.is_new_user){let url=new URL(window.location.href);url.searchParams.set("is_new_user",!0),window.location.href=url.toString()}return response}return App.events.notyf("error","Failed to create creditcard."),response},async removeCreditCard(id){let payload={id:id,properties:{is_enabled:!1}},response=await StripeServices.deleteCreditCard({payload:payload});return response.state||App.events.notyf("error","Failed to delete creditcard."),response}},customer:{}};window.StripeModel=StripeModel;